     1→/**
     2→ * Optimizer Routes
     3→ *
     4→ * REST endpoints for triggering and monitoring optimization jobs.
     5→ * Jobs are processed asynchronously via BullMQ workers.
     6→ *
     7→ * Endpoints:
     8→ * - POST /optimizer/run-assignment - Trigger train-to-route assignment optimization
     9→ * - GET /optimizer/jobs/:jobId - Get job status and results
    10→ * - POST /optimizer/tactical-schedule - Trigger tactical PM scheduling (12-week)
    11→ * - POST /optimizer/strategic-plan - Trigger strategic planning (10-year)
    12→ *
    13→ * @see specs/005-api.md Section 5.6
    14→ */
    15→
    16→import { Hono } from 'hono';
    17→import {
    18→  success,
    19→  error,
    20→  ErrorCodes,
    21→  type AppVariables,
    22→} from '../types';
    23→import { getRequestId, getRequestDuration } from '../middleware/request-context';
    24→import { isValidUuid } from '../../lib/schemas';
    25→import {
    26→  addJob,
    27→  getQueue,
    28→  QUEUE_NAMES,
    29→  type OptimizerJobData,
    30→  type TacticalSchedulerJobData,
    31→  type StrategicPlannerJobData,
    32→} from '../../lib/queue';
    33→
    34→export const optimizerRoutes = new Hono<{ Variables: AppVariables }>();
    35→
    36→// =============================================================================
    37→// Types
    38→// =============================================================================
    39→
    40→/**
    41→ * Request body for POST /optimizer/run-assignment
    42→ */
    43→interface RunAssignmentRequest {
    44→  date: string; // ISO date string (YYYY-MM-DD)
    45→  fleetId: string;
    46→  depotId?: string;
    47→  options?: {
    48→    maxSolveTimeSeconds?: number;
    49→    explanationVerbosity?: 'MINIMAL' | 'STANDARD' | 'DETAILED';
    50→  };
    51→  constraints?: {
    52→    serviceRequirements?: Record<string, number>;
    53→    unavailableTrains?: string[];
    54→    preferredAssignments?: Record<string, string>;
    55→  };
    56→}
    57→
    58→/**
    59→ * Request body for POST /optimizer/tactical-schedule
    60→ */
    61→interface TacticalScheduleRequest {
    62→  depotId?: string;
    63→  fleetId?: string;
    64→  trainIds?: string[];
    65→  horizonWeeks?: number; // Default 12
    66→  dryRun?: boolean;
    67→}
    68→
    69→/**
    70→ * Request body for POST /optimizer/strategic-plan
    71→ */
    72→interface StrategicPlanRequest {
    73→  horizonYears?: number; // Default 10
    74→  fromBaselineId?: string;
    75→  fleetId?: string;
    76→  populationSize?: number;
    77→  generations?: number;
    78→}
    79→
    80→/**
    81→ * Optimizer job status response
    82→ */
    83→type OptimizerJobStatus =
    84→  | 'waiting'
    85→  | 'active'
    86→  | 'completed'
    87→  | 'failed'
    88→  | 'delayed'
    89→  | 'unknown';
    90→
    91→// =============================================================================
    92→// Helper Functions
    93→// =============================================================================
    94→
    95→/**
    96→ * Validate ISO date string (YYYY-MM-DD)
    97→ */
    98→function isValidDateString(date: string): boolean {
    99→  if (!/^\d{4}-\d{2}-\d{2}$/.test(date)) {
   100→    return false;
   101→  }
   102→  const parsed = new Date(date);
   103→  return !isNaN(parsed.getTime());
   104→}
   105→
   106→/**
   107→ * Get detailed job information including result
   108→ */
   109→async function getDetailedJob(
   110→  queueName: typeof QUEUE_NAMES[keyof typeof QUEUE_NAMES],
   111→  jobId: string
   112→): Promise<{
   113→  id: string;
   114→  status: OptimizerJobStatus;
   115→  progress?: unknown;
   116→  result?: unknown;
   117→  failedReason?: string;
   118→  startedAt?: string;
   119→  completedAt?: string;
   120→  attemptsMade?: number;
   121→} | null> {
   122→  const queue = getQueue(queueName);
   123→  const job = await queue.getJob(jobId);
   124→
   125→  if (!job) return null;
   126→
   127→  const state = await job.getState();
   128→  const result = job.returnvalue;
   129→  const failedReason = job.failedReason;
   130→  const progress = job.progress;
   131→  const processedOn = job.processedOn;
   132→  const finishedOn = job.finishedOn;
   133→
   134→  return {
   135→    id: job.id!,
   136→    status: (state as OptimizerJobStatus) || 'unknown',
   137→    ...(progress !== undefined && { progress }),
   138→    ...(result !== undefined && { result }),
   139→    ...(failedReason && { failedReason }),
   140→    ...(processedOn && { startedAt: new Date(processedOn).toISOString() }),
   141→    ...(finishedOn && { completedAt: new Date(finishedOn).toISOString() }),
   142→    attemptsMade: job.attemptsMade,
   143→  };
   144→}
   145→
   146→/**
   147→ * Estimate completion time based on job complexity
   148→ */
   149→function estimateCompletionSeconds(trainCount: number, routeCount: number): number {
   150→  // Rough estimate: base time + scaling factor
   151→  const baseTime = 10;
   152→  const scaleFactor = 0.5;
   153→  return Math.ceil(baseTime + (trainCount * routeCount * scaleFactor) / 1000);
   154→}
   155→
   156→// =============================================================================
   157→// Routes
   158→// =============================================================================
   159→
   160→/**
   161→ * POST /optimizer/run-assignment
   162→ *
   163→ * Trigger run assignment optimization for a specific date and fleet.
   164→ * The optimization is performed asynchronously and returns a job ID
   165→ * that can be used to check status and retrieve results.
   166→ */
   167→optimizerRoutes.post('/optimizer/run-assignment', async (c) => {
   168→  const requestId = getRequestId(c);
   169→
   170→  // Parse request body
   171→  let body: RunAssignmentRequest;
   172→  try {
   173→    body = await c.req.json();
   174→  } catch {
   175→    return c.json(
   176→      error(ErrorCodes.VALIDATION_ERROR, 'Invalid JSON body', requestId),
   177→      400
   178→    );
   179→  }
   180→
   181→  // Validate required fields
   182→  if (!body.date) {
   183→    return c.json(
   184→      error(ErrorCodes.VALIDATION_ERROR, 'date is required', requestId, {
   185→        field: 'date',
   186→      }),
   187→      400
   188→    );
   189→  }
   190→
   191→  if (!isValidDateString(body.date)) {
   192→    return c.json(
   193→      error(
   194→        ErrorCodes.VALIDATION_ERROR,
   195→        'Invalid date format. Expected YYYY-MM-DD',
   196→        requestId,
   197→        { field: 'date', value: body.date }
   198→      ),
   199→      400
   200→    );
   201→  }
   202→
   203→  if (!body.fleetId) {
   204→    return c.json(
   205→      error(ErrorCodes.VALIDATION_ERROR, 'fleetId is required', requestId, {
   206→        field: 'fleetId',
   207→      }),
   208→      400
   209→    );
   210→  }
   211→
   212→  if (!isValidUuid(body.fleetId)) {
   213→    return c.json(
   214→      error(
   215→        ErrorCodes.VALIDATION_ERROR,
   216→        'Invalid fleetId format. Expected UUID',
   217→        requestId,
   218→        { field: 'fleetId', value: body.fleetId }
   219→      ),
   220→      400
   221→    );
   222→  }
   223→
   224→  // Validate options if provided
   225→  const maxSolveTimeSeconds = body.options?.maxSolveTimeSeconds ?? 30;
   226→  if (maxSolveTimeSeconds < 1 || maxSolveTimeSeconds > 300) {
   227→    return c.json(
   228→      error(
   229→        ErrorCodes.VALIDATION_ERROR,
   230→        'maxSolveTimeSeconds must be between 1 and 300',
   231→        requestId,
   232→        { field: 'options.maxSolveTimeSeconds', value: maxSolveTimeSeconds }
   233→      ),
   234→      400
   235→    );
   236→  }
   237→
   238→  const validVerbosityLevels = ['MINIMAL', 'STANDARD', 'DETAILED'];
   239→  const verbosity = body.options?.explanationVerbosity ?? 'STANDARD';
   240→  if (!validVerbosityLevels.includes(verbosity)) {
   241→    return c.json(
   242→      error(
   243→        ErrorCodes.VALIDATION_ERROR,
   244→        `explanationVerbosity must be one of: ${validVerbosityLevels.join(', ')}`,
   245→        requestId,
   246→        { field: 'options.explanationVerbosity', value: verbosity }
   247→      ),
   248→      400
   249→    );
   250→  }
   251→
   252→  // Build job data
   253→  const jobData: OptimizerJobData = {
   254→    date: body.date,
   255→    fleetId: body.fleetId,
   256→    timeoutMs: maxSolveTimeSeconds * 1000,
   257→    ...(body.constraints && { constraints: body.constraints }),
   258→  };
   259→
   260→  // Add job to queue
   261→  const { id: jobId } = await addJob(
   262→    QUEUE_NAMES.OPTIMIZER,
   263→    'run-assignment',
   264→    jobData,
   265→    {
   266→      priority: 1, // High priority for run assignments
   267→    }
   268→  );
   269→
   270→  // Estimate completion time (this would be more accurate with fleet size info)
   271→  const estimatedCompletionSeconds = estimateCompletionSeconds(50, 10);
   272→
   273→  return c.json(
   274→    success(
   275→      {
   276→        jobId,
   277→        status: 'QUEUED',
   278→        estimatedCompletionSeconds,
   279→      },
   280→      {
   281→        timing: { durationMs: getRequestDuration(c) },
   282→      }
   283→    ),
   284→    202
   285→  );
   286→});
   287→
   288→/**
   289→ * GET /optimizer/jobs/:jobId
   290→ *
   291→ * Get the status and results of an optimizer job.
   292→ */
   293→optimizerRoutes.get('/optimizer/jobs/:jobId', async (c) => {
   294→  const requestId = getRequestId(c);
   295→  const jobId = c.req.param('jobId');
   296→
   297→  // Try to find job in optimizer queue first
   298→  let job = await getDetailedJob(QUEUE_NAMES.OPTIMIZER, jobId);
   299→
   300→  // If not found, try tactical scheduler queue
   301→  if (!job) {
   302→    job = await getDetailedJob(QUEUE_NAMES.TACTICAL_SCHEDULER, jobId);
   303→  }
   304→
   305→  // If not found, try strategic planner queue
   306→  if (!job) {
   307→    job = await getDetailedJob(QUEUE_NAMES.STRATEGIC_PLANNER, jobId);
   308→  }
   309→
   310→  if (!job) {
   311→    return c.json(
   312→      error(ErrorCodes.NOT_FOUND, `Job ${jobId} not found`, requestId),
   313→      404
   314→    );
   315→  }
   316→
   317→  // Map internal status to API status
   318→  const statusMap: Record<string, string> = {
   319→    waiting: 'QUEUED',
   320→    delayed: 'QUEUED',
   321→    active: 'PROCESSING',
   322→    completed: 'COMPLETED',
   323→    failed: 'FAILED',
   324→  };
   325→
   326→  const apiStatus = statusMap[job.status] || 'UNKNOWN';
   327→
   328→  // Build response based on job status
   329→  interface JobResponse {
   330→    jobId: string;
   331→    status: string;
   332→    startedAt?: string;
   333→    completedAt?: string;
   334→    progress?: unknown;
   335→    result?: unknown;
   336→    error?: {
   337→      message: string;
   338→      attemptsMade?: number;
   339→    };
   340→  }
   341→
   342→  const response: JobResponse = {
   343→    jobId: job.id,
   344→    status: apiStatus,
   345→    ...(job.startedAt && { startedAt: job.startedAt }),
   346→    ...(job.completedAt && { completedAt: job.completedAt }),
   347→  };
   348→
   349→  // Include progress for active jobs
   350→  if (job.status === 'active' && job.progress) {
   351→    response.progress = job.progress;
   352→  }
   353→
   354→  // Include result for completed jobs
   355→  if (job.status === 'completed' && job.result) {
   356→    response.result = job.result;
   357→  }
   358→
   359→  // Include error for failed jobs
   360→  if (job.status === 'failed' && job.failedReason) {
   361→    response.error = {
   362→      message: job.failedReason,
   363→      attemptsMade: job.attemptsMade,
   364→    };
   365→  }
   366→
   367→  return c.json(
   368→    success(response, {
   369→      timing: { durationMs: getRequestDuration(c) },
   370→    })
   371→  );
   372→});
   373→
   374→/**
   375→ * POST /optimizer/tactical-schedule
   376→ *
   377→ * Trigger tactical PM scheduling for a 12-week horizon.
   378→ * Optimizes PM placement considering track availability,
   379→ * material constraints, and man-hour capacity.
   380→ */
   381→optimizerRoutes.post('/optimizer/tactical-schedule', async (c) => {
   382→  const requestId = getRequestId(c);
   383→
   384→  // Parse request body
   385→  let body: TacticalScheduleRequest;
   386→  try {
   387→    body = await c.req.json();
   388→  } catch {
   389→    body = {}; // Allow empty body for default parameters
   390→  }
   391→
   392→  // Validate depotId if provided
   393→  if (body.depotId && !isValidUuid(body.depotId)) {
   394→    return c.json(
   395→      error(
   396→        ErrorCodes.VALIDATION_ERROR,
   397→        'Invalid depotId format. Expected UUID',
   398→        requestId,
   399→        { field: 'depotId', value: body.depotId }
   400→      ),
   401→      400
   402→    );
   403→  }
   404→
   405→  // Validate fleetId if provided
   406→  if (body.fleetId && !isValidUuid(body.fleetId)) {
   407→    return c.json(
   408→      error(
   409→        ErrorCodes.VALIDATION_ERROR,
   410→        'Invalid fleetId format. Expected UUID',
   411→        requestId,
   412→        { field: 'fleetId', value: body.fleetId }
   413→      ),
   414→      400
   415→    );
   416→  }
   417→
   418→  // Validate trainIds if provided
   419→  if (body.trainIds) {
   420→    for (const trainId of body.trainIds) {
   421→      if (!isValidUuid(trainId)) {
   422→        return c.json(
   423→          error(
   424→            ErrorCodes.VALIDATION_ERROR,
   425→            'Invalid trainId format in trainIds array',
   426→            requestId,
   427→            { field: 'trainIds', invalidValue: trainId }
   428→          ),
   429→          400
   430→        );
   431→      }
   432→    }
   433→  }
   434→
   435→  // Validate horizonWeeks
   436→  const horizonWeeks = body.horizonWeeks ?? 12;
   437→  if (horizonWeeks < 1 || horizonWeeks > 52) {
   438→    return c.json(
   439→      error(
   440→        ErrorCodes.VALIDATION_ERROR,
   441→        'horizonWeeks must be between 1 and 52',
   442→        requestId,
   443→        { field: 'horizonWeeks', value: horizonWeeks }
   444→      ),
   445→      400
   446→    );
   447→  }
   448→
   449→  // Build job data
   450→  const jobData: TacticalSchedulerJobData = {
   451→    fleetId: body.fleetId,
   452→    trainIds: body.trainIds,
   453→    horizonWeeks,
   454→    dryRun: body.dryRun ?? false,
   455→  };
   456→
   457→  // Add job to queue
   458→  const { id: jobId } = await addJob(
   459→    QUEUE_NAMES.TACTICAL_SCHEDULER,
   460→    'tactical-schedule',
   461→    jobData
   462→  );
   463→
   464→  return c.json(
   465→    success(
   466→      {
   467→        jobId,
   468→        status: 'QUEUED',
   469→        horizonWeeks,
   470→        dryRun: body.dryRun ?? false,
   471→      },
   472→      {
   473→        timing: { durationMs: getRequestDuration(c) },
   474→      }
   475→    ),
   476→    202
   477→  );
   478→});
   479→
   480→/**
   481→ * POST /optimizer/strategic-plan
   482→ *
   483→ * Trigger strategic planning for a 10-year horizon.
   484→ * Uses genetic algorithm to optimize long-term PM scheduling
   485→ * and resource allocation.
   486→ */
   487→optimizerRoutes.post('/optimizer/strategic-plan', async (c) => {
   488→  const requestId = getRequestId(c);
   489→
   490→  // Parse request body
   491→  let body: StrategicPlanRequest;
   492→  try {
   493→    body = await c.req.json();
   494→  } catch {
   495→    body = {}; // Allow empty body for default parameters
   496→  }
   497→
   498→  // Validate fromBaselineId if provided
   499→  if (body.fromBaselineId && !isValidUuid(body.fromBaselineId)) {
   500→    return c.json(
   501→      error(
   502→        ErrorCodes.VALIDATION_ERROR,
   503→        'Invalid fromBaselineId format. Expected UUID',
   504→        requestId,
   505→        { field: 'fromBaselineId', value: body.fromBaselineId }
   506→      ),
   507→      400
   508→    );
   509→  }
   510→
   511→  // Validate fleetId if provided
   512→  if (body.fleetId && !isValidUuid(body.fleetId)) {
   513→    return c.json(
   514→      error(
   515→        ErrorCodes.VALIDATION_ERROR,
   516→        'Invalid fleetId format. Expected UUID',
   517→        requestId,
   518→        { field: 'fleetId', value: body.fleetId }
   519→      ),
   520→      400
   521→    );
   522→  }
   523→
   524→  // Validate horizonYears
   525→  const horizonYears = body.horizonYears ?? 10;
   526→  if (horizonYears < 1 || horizonYears > 15) {
   527→    return c.json(
   528→      error(
   529→        ErrorCodes.VALIDATION_ERROR,
   530→        'horizonYears must be between 1 and 15',
   531→        requestId,
   532→        { field: 'horizonYears', value: horizonYears }
   533→      ),
   534→      400
   535→    );
   536→  }
   537→
   538→  // Validate GA parameters
   539→  const populationSize = body.populationSize ?? 100;
   540→  if (populationSize < 10 || populationSize > 1000) {
   541→    return c.json(
   542→      error(
   543→        ErrorCodes.VALIDATION_ERROR,
   544→        'populationSize must be between 10 and 1000',
   545→        requestId,
   546→        { field: 'populationSize', value: populationSize }
   547→      ),
   548→      400
   549→    );
   550→  }
   551→
   552→  const generations = body.generations ?? 500;
   553→  if (generations < 10 || generations > 5000) {
   554→    return c.json(
   555→      error(
   556→        ErrorCodes.VALIDATION_ERROR,
   557→        'generations must be between 10 and 5000',
   558→        requestId,
   559→        { field: 'generations', value: generations }
   560→      ),
   561→      400
   562→    );
   563→  }
   564→
   565→  // Build job data
   566→  const jobData: StrategicPlannerJobData = {
   567→    fleetId: body.fleetId,
   568→    horizonYears,
   569→    populationSize,
   570→    generations,
   571→  };
   572→
   573→  // Add job to queue
   574→  const { id: jobId } = await addJob(
   575→    QUEUE_NAMES.STRATEGIC_PLANNER,
   576→    'strategic-plan',
   577→    jobData
   578→  );
   579→
   580→  // Estimate completion time for strategic planning (much longer)
   581→  const estimatedCompletionSeconds = Math.ceil(
   582→    (populationSize * generations) / 100 + 60
   583→  );
   584→
   585→  return c.json(
   586→    success(
   587→      {
   588→        jobId,
   589→        status: 'QUEUED',
   590→        horizonYears,
   591→        populationSize,
   592→        generations,
   593→        estimatedCompletionSeconds,
   594→      },
   595→      {
   596→        timing: { durationMs: getRequestDuration(c) },
