   170→    pmDrifts: [], // PM drift details would need to be stored/retrieved separately
   171→    avgPmDriftDays: drift.avgPmDriftDays ? parseFloat(drift.avgPmDriftDays) : 0,
   172→    maxPmDriftDays: drift.maxPmDriftDays ?? 0,
   173→    requiresReplan: drift.requiresReplan,
   174→    replanReason: drift.replanReason,
