/**
 * Export Routes
 *
 * REST endpoints for exporting PM schedules (Excel/CSV) and generating reports (PDF).
 * Uses async job processing with status polling.
 *
 * Key endpoints:
 * - POST /export/pm-schedule - Queue PM schedule export
 * - POST /export/report - Queue report generation
 * - GET /export/:jobId - Get export job status and download URL
 * - GET /export/jobs - List export jobs for current user
 *
 * @see specs/005-api.md Section 5.15
 */

import { Hono } from 'hono';
import {
  success,
  paginatedSuccess,
  error,
  parsePaginationQuery,
  ErrorCodes,
  type AppVariables,
} from '../types';
import { getRequestId, getRequestDuration } from '../middleware/request-context';
import {
  getExportService,
  type PmScheduleExportRequest,
  type ReportExportRequest,
  type ExportJobStatus,
  type ReportType,
} from '../../services/export';

// Singleton service instance
let exportService: ReturnType<typeof getExportService> | null = null;

function getService(): ReturnType<typeof getExportService> {
  if (!exportService) {
    exportService = getExportService();
  }
  return exportService;
}

export const exportRoutes = new Hono<{ Variables: AppVariables }>();

/**
 * POST /export/pm-schedule
 *
 * Queue a PM schedule export job.
 *
 * Request Body:
 * - format: Export format ('xlsx' or 'csv')
 * - filters: Optional filters (depotId, fleetId, trainId, fromDate, toDate, status, pmTypeId, scenarioId)
 * - columns: Optional list of columns to include
 *
 * Returns 202 Accepted with job ID for polling.
 */
exportRoutes.post('/export/pm-schedule', async (c) => {
  const requestId = getRequestId(c);
  const service = getService();

  try {
    const body = await c.req.json();

    // Validate required fields
    if (!body.format) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, 'format is required', requestId, {
          field: 'format',
          expected: ['xlsx', 'csv'],
        }),
        400
      );
    }

    if (!['xlsx', 'csv'].includes(body.format)) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, 'Invalid format', requestId, {
          field: 'format',
          expected: ['xlsx', 'csv'],
          received: body.format,
        }),
        400
      );
