/**
 * Baseline Assumption Routes
 *
 * REST endpoints for managing PM baseline assumptions during cold start
 * data migration. Includes manual review queue for LOW/ESTIMATED confidence
 * assumptions.
 *
 * Key features:
 * - CRUD operations for baseline assumptions
 * - Review queue for manual verification
 * - Inference rules (from commissioning date, higher PM)
 * - Review/approval workflow
 *
 * @see specs/003-database-schema.md Section 3.2.6
 * @see ADR-014: PM History Assumptions for Cold Start
 */

import { Hono } from 'hono';
import {
  success,
  paginatedSuccess,
  error,
  parsePaginationQuery,
  ErrorCodes,
  type AppVariables,
} from '../types';
import { getRequestId, getRequestDuration } from '../middleware/request-context';
import {
  getBaselineAssumptionService,
  type AssumptionFilters,
  type AssumptionType,
  type AssumptionConfidenceLevel as ConfidenceLevel,
} from '../../services';
import { isValidUuid } from '../../lib/schemas';
import { NotFoundError, ValidationError, ConflictError } from '../../lib/errors';

// Singleton service instance
let assumptionService: ReturnType<typeof getBaselineAssumptionService> | null = null;

function getService(): ReturnType<typeof getBaselineAssumptionService> {
  if (!assumptionService) {
    assumptionService = getBaselineAssumptionService();
  }
  return assumptionService;
}

export const baselineAssumptionRoutes = new Hono<{ Variables: AppVariables }>();

// =============================================================================
// Review Queue Endpoints
// =============================================================================

/**
 * GET /baseline-assumptions/review-queue
 *
 * Get assumptions requiring manual review.
 * Returns assumptions with LOW or ESTIMATED confidence that have not been reviewed.
 *
 * Query Parameters:
 * - page: Page number (default: 1)
 * - pageSize: Items per page (default: 20, max: 100)
 * - sortBy: Sort field (createdAt, confidenceLevel, trainNumber)
 * - sortOrder: Sort direction (asc, desc) - default: asc (oldest first)
 */
baselineAssumptionRoutes.get('/baseline-assumptions/review-queue', async (c) => {
  const service = getService();

  const pagination = parsePaginationQuery({
    page: c.req.query('page') ? Number(c.req.query('page')) : undefined,
    pageSize: c.req.query('pageSize') ? Number(c.req.query('pageSize')) : undefined,
    sort: c.req.query('sortBy')
      ? `${c.req.query('sortBy')}:${c.req.query('sortOrder') ?? 'asc'}`
      : undefined,
  });

  const result = await service.getReviewQueue({
    page: pagination.page,
    pageSize: Math.min(pagination.pageSize, 100),
    sortBy: (c.req.query('sortBy') as 'createdAt' | 'confidenceLevel' | 'trainNumber') ?? 'createdAt',
    sortOrder: (c.req.query('sortOrder') as 'asc' | 'desc') ?? 'asc',
  });

  return c.json(
    paginatedSuccess(
      result.items.map((a) => mapAssumptionToResponse(a as unknown as AssumptionWithDetailsInput)),
      {
        page: result.page,
        pageSize: result.pageSize,
        totalItems: result.total,
      },
      { durationMs: getRequestDuration(c) }
    )
  );
});

